function renderExport(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),jobs=state.exportJobs||[];p.innerHTML='<h3>后台导出队列</h3>'+field('exportName','文件名',state.project.name.replace(/\s+/g,'-'),'text')+'<label class="field">类型<select id="exportKind"><option value="video">视频 MP4</option><option value="audio">纯音频</option><option value="fcpxml">FCPXML</option><option value="premiere-xml">Premiere XML</option><option value="edl">EDL</option><option value="jianying">剪映草稿（实验）</option></select></label><div class="row"><label class="field">范围<select id="exportRange"><option value="full">完整时间线</option><option value="zone">In/Out 区间</option></select></label><label class="field">分辨率<select id="exportResolution"><option value="original">原始</option><option value="1080p">1080p</option><option value="720p">720p</option><option value="480p">480p</option></select></label></div><div class="row"><label class="field">帧率<select id="exportFps"><option value="">跟随时间线</option><option>24</option><option>25</option><option>30</option><option>50</option><option>60</option></select></label><label class="field">音频格式<select id="exportAudioFormat"><option>wav</option><option>flac</option><option>mp3</option><option>m4a</option></select></label></div><label class="field"><input id="exportCaptions" type="checkbox"> 烧录字幕</label><button class="save" id="submitExport">开始后台导出</button><p class="hint">任务在独立本地进程运行；关闭面板或 Codex 对话不会丢失任务记录。</p><h3 style="margin-top:18px">最近任务</h3>'+jobs.map(j=>'<div class="caption"><b>'+esc(j.kind)+' · '+esc(j.status)+'</b><small>'+esc(j.phase)+' · '+j.progress+'%</small><div style="height:4px;background:#292d35;margin:6px 0"><i style="display:block;height:100%;width:'+j.progress+'%;background:#47ba83"></i></div><small>'+esc(j.outputPath)+'</small>'+(j.error?'<small style="color:#ff8875">'+esc(j.error.split('\\n')[0])+'</small>':'')+(!['completed','failed','cancelled'].includes(j.status)?'<button class="action" data-cancel-export="'+j.id+'">取消</button>':'')+'</div>').join('');$('#submitExport').onclick=()=>edit({kind:'export-submit',exportKind:$('#exportKind').value,name:$('#f-exportName').value,options:{range:$('#exportRange').value,resolution:$('#exportResolution').value,frameRate:$('#exportFps').value?+$('#exportFps').value:undefined,format:$('#exportAudioFormat').value,burnCaptions:$('#exportCaptions').checked}});document.querySelectorAll('[data-cancel-export]').forEach(b=>b.onclick=()=>edit({kind:'export-cancel',jobId:b.dataset.cancelExport}))}
function renderTranscript(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),m=transcriptModel();if(!m){p.innerHTML='<p class="hint">项目中没有带词级时间戳的素材。请先运行本地转录。</p>';return}p.innerHTML='<h3>文字稿 · '+esc(m.asset.name)+'</h3><p class="hint">↑↓ 重排源片段，× 删除；保存后同时重建视频、音频和逐词字幕。</p>'+m.segments.map((s,i)=>'<div class="caption"><small>'+fmt(s.sourceStart)+'–'+fmt(s.sourceEnd)+'</small><div>'+esc(s.label)+'</div><button data-up="'+i+'">↑</button><button data-down="'+i+'">↓</button><button data-remove="'+i+'">×</button></div>').join('')+'<button class="save" id="saveTranscript">应用文字剪辑</button>';const rerender=()=>{state.timeline.transcriptEdit={...m.config,assetId:m.asset.id,segments:m.segments};renderTranscript()};document.querySelectorAll('[data-up]').forEach(b=>b.onclick=()=>{const i=+b.dataset.up;if(i){[m.segments[i-1],m.segments[i]]=[m.segments[i],m.segments[i-1]];rerender()}});document.querySelectorAll('[data-down]').forEach(b=>b.onclick=()=>{const i=+b.dataset.down;if(i<m.segments.length-1){[m.segments[i+1],m.segments[i]]=[m.segments[i],m.segments[i+1]];rerender()}});document.querySelectorAll('[data-remove]').forEach(b=>b.onclick=()=>{if(m.segments.length<=1){$('#error').textContent='至少保留一个文字片段';return}m.segments.splice(+b.dataset.remove,1);rerender()});$('#saveTranscript').onclick=()=>edit({kind:'transcript-sequence',assetId:m.asset.id,segments:m.segments,videoTrackName:m.config.videoTrackName||'V1',audioTrackName:m.config.audioTrackName||'A1',includeVideo:!!m.config.videoTrackName,includeAudio:!!m.config.audioTrackName,gapSeconds:m.config.gapSeconds||0})}
function renderMarkers(){const colors={red:'#e5484d',orange:'#e9863f',yellow:'#d6ad28',green:'#3fb55b',blue:'#4f8cff',purple:'#9b6bcc'},markers=state.timeline.markers||[];$('#markers').innerHTML=markers.map(m=>'<button class="marker" data-marker="'+m.id+'" title="'+esc(m.label||m.name||'Marker')+' · '+fmt(m.time)+'" style="left:'+(m.time*pps)+'px;--marker:'+(colors[m.color]||colors.red)+'"></button>').join('');document.querySelectorAll('[data-marker]').forEach(el=>{const marker=markers.find(m=>m.id===el.dataset.marker);el.onclick=e=>{e.stopPropagation();if(e.shiftKey){const label=prompt('重命名标记',marker.label||marker.name||'Marker');if(label!==null)edit({kind:'marker-update',markerId:marker.id,changes:{label}});return}const v=$('#preview');v.currentTime=marker.time;syncPlayhead()};el.oncontextmenu=e=>{e.preventDefault();if(confirm('删除标记 “'+(marker.label||marker.name||'Marker')+'” ？'))edit({kind:'marker-delete',markerId:marker.id})}})}
function renderTimeline(){renderMarkers();const d=Math.max(1,state.duration),w=Math.max(innerWidth,d*pps+180);$('#canvas').style.width=w+'px';$('#ruler').innerHTML=Array.from({length:Math.ceil(d/5)+1},(_,i)=>'<span class="tick" style="left:'+(118+i*5*pps)+'px">'+i*5+'s</span>').join('');$('#tracks').innerHTML=state.timeline.tracks.map(t=>'<div class="track"><div class="track-name"><b>'+esc(t.name)+'</b><div><button data-mute="'+t.id+'">'+(t.muted?'×':t.type==='audio'?'🔊':'👁')+'</button><button data-lock="'+t.id+'">'+(t.locked?'🔒':'🔓')+'</button><button data-track-delete="'+t.id+'">⌫</button></div></div><div class="lane">'+t.items.map(i=>{const a=state.project.assets.find(x=>x.id===i.assetId)||{};const cls=t.type==='audio'?'audio':a.type==='motion-graphic'?'mg':'',selectedLink=findById(selected)?.item.linkGroupId;const wave=t.type==='audio'?'background-image:url(&quot;/waveform?token='+encodeURIComponent(token)+'&assetId='+encodeURIComponent(a.id)+'&quot;);':'';return '<button class="clip '+cls+' '+(selected===i.id||(i.linkGroupId&&i.linkGroupId===selectedLink)?'selected':'')+'" data-id="'+i.id+'" style="left:'+(i.start*pps)+'px;width:'+Math.max(28,i.duration*pps)+'px;'+wave+'"><i class="trim-handle left" data-edge="left"></i><span>'+esc(i.label||a.name||'clip')+'</span><small>'+(i.linkGroupId?'🔗 ':'')+fmt(i.duration)+'</small><i class="trim-handle right" data-edge="right"></i></button>'}).join('')+'</div></div>').join('');document.querySelectorAll('[data-mute]').forEach(b=>b.onclick=()=>{const t=state.timeline.tracks.find(x=>x.id===b.dataset.mute);edit({kind:'track-update',trackId:t.id,changes:{muted:!t.muted}})});document.querySelectorAll('[data-lock]').forEach(b=>b.onclick=()=>{const t=state.timeline.tracks.find(x=>x.id===b.dataset.lock);edit({kind:'track-update',trackId:t.id,changes:{locked:!t.locked}})});document.querySelectorAll('[data-track-delete]').forEach(b=>b.onclick=()=>edit({kind:'track-delete',trackId:b.dataset.trackDelete}));document.querySelectorAll('.clip').forEach(el=>{el.onclick=e=>{if(e.target.dataset.edge)return;e.stopPropagation();if(selectionMode)return edit({kind:'context-add',reference:{type:'item',itemId:el.dataset.id}});selected=el.dataset.id;tab='clip';const f=findById(selected),v=$('#preview');if(f&&v.src)v.currentTime=Math.min(v.duration||Infinity,f.item.start+0.05);render()};el.onpointerdown=e=>{if(!selectionMode)startMove(e)}});document.querySelectorAll('.trim-handle').forEach(el=>el.onpointerdown=e=>{if(!selectionMode)startTrim(e)});syncPlayhead()}
function findById(id){for(const t of state.timeline.tracks){const i=t.items.find(x=>x.id===id);if(i)return{item:i,track:t,asset:state.project.assets.find(a=>a.id===i.assetId)}}}
function findItem(){return findById(selected)}
function field(k,l,v,t='number'){return '<label class="field">'+l+'<input id="f-'+k+'" type="'+t+'" step="0.01" value="'+esc(v)+'"></label>'}
function renderDuplicates(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),a=state.duplicateAnalysis,pairs=a?.pairs||[];p.innerHTML='<h3>本地重复镜头检测</h3>'+field('duplicateThreshold','相似度阈值',a?.threshold??.92)+'<button class="action" id="analyzeDuplicates">扫描时间线代表帧</button>'+(a?'<div class="caption"><b>'+pairs.length+' 组重复候选</b><small>已分析 '+a.samples+' 个视频片段 · 不会自动删除</small></div>'+pairs.map(x=>'<label class="caption"><input type="checkbox" data-duplicate="'+x.duplicateItemId+'" checked> '+esc(x.second.label)+'<small>与 '+esc(x.first.label)+' 相似 '+Math.round(x.similarity*100)+'% · '+fmt(x.second.timelineStart)+'</small></label>').join('')+(pairs.length?'<button class="save" id="removeDuplicates">保留首次并 Ripple 删除勾选重复</button>':''):'<p class="hint">抽取每个时间线视频片段的代表帧并在本机计算感知哈希，特别适合发现重复使用的走路、洗手或空镜。</p>');$('#analyzeDuplicates').onclick=()=>edit({kind:'duplicates-analyze',options:{threshold:+$('#f-duplicateThreshold').value,minDuration:.2}});$('#removeDuplicates')?.addEventListener('click',()=>{const duplicateItemIds=[...document.querySelectorAll('[data-duplicate]:checked')].map(x=>x.dataset.duplicate);if(!duplicateItemIds.length)return;edit({kind:'duplicates-remove',duplicateItemIds,ripple:true})})}
function renderReframe(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f||f.asset?.type!=='video'){p.innerHTML='<p class="hint">请先选择时间线中的视频片段。</p>';return}const item=f.item,plan=state.reframePlan?.itemId===item.id?state.reframePlan:item.reframe?{...item.reframe,itemId:item.id,timelineDuration:item.duration}:null,ks=plan?.keyframes||[],points=ks.map(k=>(10+280*k.time/Math.max(.01,item.duration))+','+(95-80*k.focusX)).join(' ');p.innerHTML='<h3>本地智能重构图</h3><div class="row">'+field('reframeFps','分析采样 fps',4)+field('reframeSmooth','轨迹平滑',.72)+'</div><div class="row">'+field('reframeWidth','目标宽',state.timeline.width)+field('reframeHeight','目标高',state.timeline.height)+'</div><button class="action" id="analyzeReframe">分析主体轨迹，不修改项目</button>'+(plan?'<div class="caption"><b>'+esc(plan.detector||'manual')+' · '+ks.length+' 个焦点</b><small>'+(plan.framesAnalyzed?plan.framesAnalyzed+' 帧 · 平均置信度 '+plan.averageConfidence:'已应用/手动轨迹')+'</small></div><svg viewBox="0 0 300 110" style="width:100%;height:110px;background:#0c0e12;border:1px solid #2b2e36"><path d="M10 95H290M10 15V95" stroke="#343944"/><polyline points="'+points+'" fill="none" stroke="#47ba83" stroke-width="3"/></svg><p class="hint">曲线纵向表示画面焦点 X；每个点都可手动改成 0–1。</p>'+ks.map((k,i)=>'<div class="row" data-reframe-kf="'+i+'">'+field('rfTime'+i,'时间',k.time)+field('rfX'+i,'焦点 X',k.focusX)+field('rfY'+i,'焦点 Y',k.focusY)+'</div>').join('')+'<button class="save" id="applyReframe">确认应用动态裁切</button>':'<p class="hint">使用低分辨率显著性和运动重心，不上传素材；分析结果先审后用。</p>')+(item.reframe?'<button class="action danger" id="clearReframe">清除动态构图</button>':'');$('#analyzeReframe').onclick=()=>edit({kind:'reframe-analyze',itemId:item.id,options:{targetWidth:+$('#f-reframeWidth').value,targetHeight:+$('#f-reframeHeight').value,sampleFps:+$('#f-reframeFps').value,smoothing:+$('#f-reframeSmooth').value,analysisWidth:160,keyframeInterval:.5}});if(plan)$('#applyReframe').onclick=()=>edit({kind:'reframe-apply',itemId:item.id,plan,keyframes:ks.map((k,i)=>({time:+$('#f-rfTime'+i).value,focusX:+$('#f-rfX'+i).value,focusY:+$('#f-rfY'+i).value,confidence:k.confidence}))});$('#clearReframe')?.addEventListener('click',()=>edit({kind:'reframe-clear',itemId:item.id}))}
function keyframePanel(item){const ks=item.transform?.keyframes||[],vals=ks.filter(k=>Number.isFinite(k.x));let points='';if(vals.length){const min=Math.min(...vals.map(k=>k.x)),max=Math.max(...vals.map(k=>k.x)),span=Math.max(1,max-min);points=vals.map(k=>(10+280*k.time/Math.max(.01,item.duration))+','+(95-80*(k.x-min)/span)).join(' ')}const es=['linear','ease-in','ease-out','ease-in-out','hold','bezier'];return '<h3>关键帧曲线 · X</h3><svg viewBox="0 0 300 110" style="width:100%;height:110px;background:#0c0e12;border:1px solid #2b2e36"><path d="M10 95H290M10 15V95" stroke="#343944"/><polyline points="'+points+'" fill="none" stroke="#ff6b35" stroke-width="3"/></svg><p class="hint">每行：时间；X/Y/缩放/旋转/透明度；缓动。</p>'+ks.map((k,i)=>'<div data-kf="'+i+'" style="padding:7px 0;border-bottom:1px solid #2b2e36"><input data-v="time" type="number" step=".01" value="'+k.time+'" style="width:25%"><button data-del="'+i+'" style="float:right">×</button><div class="row">'+['x','y','scale','rotation','opacity'].map(v=>'<input data-v="'+v+'" type="number" step=".01" placeholder="'+v+'" value="'+esc(k[v]??'')+'">').join('')+'</div><select data-v="easing" style="width:100%">'+es.map(e=>'<option '+(e===(k.easing||'linear')?'selected':'')+'>'+e+'</option>').join('')+'</select></div>').join('')+'<button class="action" id="addKf">＋ 当前时间添加</button><button class="save" id="saveKf">保存关键帧</button>'}
function renderKeyframes(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f){p.innerHTML='<p class="hint">请先选择片段。</p>';return}const item=f.item;p.innerHTML=keyframePanel(item);document.querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>{item.transform.keyframes.splice(+b.dataset.del,1);renderKeyframes()});$('#addKf').onclick=()=>{item.transform||={};item.transform.keyframes||=[];item.transform.keyframes.push({time:+Math.max(0,Math.min(item.duration,($('#preview').currentTime||item.start)-item.start)).toFixed(2),x:item.transform.x??0,y:item.transform.y??0,scale:1,rotation:0,opacity:1,easing:'ease-in-out'});item.transform.keyframes.sort((a,b)=>a.time-b.time);renderKeyframes()};$('#saveKf').onclick=()=>edit({kind:'keyframes',itemId:item.id,keyframes:[...document.querySelectorAll('[data-kf]')].map(row=>{const k={};row.querySelectorAll('[data-v]').forEach(input=>{if(input.dataset.v==='easing')k.easing=input.value;else if(input.value!=='')k[input.dataset.v]=+input.value});return k})})}
function renderShader(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f){p.innerHTML='<p class="hint">请先选择视频片段。</p>';return}const fx=(f.item.effects||[]).find(e=>e.type==='glsl')||{},fallback='precision mediump float;\\nuniform sampler2D u_texture;\\nuniform float u_time;\\nuniform float u_progress;\\nuniform vec2 u_resolution;\\nvarying vec2 v_texCoord;\\nvoid main(){\\n  vec4 c=texture2D(u_texture,v_texCoord);\\n  gl_FragColor=c;\\n}';p.innerHTML='<h3>WebGL Fragment Shader</h3><label class="field">名称<input id="shaderName" value="'+esc(fx.name||'Custom GLSL')+'"></label><label class="field">Uniforms JSON<textarea id="shaderUniforms" style="width:100%;height:70px;background:#0f1115;color:white">'+esc(JSON.stringify(fx.uniforms||{},null,2))+'</textarea></label><label class="field">GLSL 源码<textarea id="shaderSource" spellcheck="false" style="width:100%;height:260px;background:#0f1115;color:#9fe6c4;font:11px monospace">'+esc(fx.source||fallback)+'</textarea></label><button class="save" id="saveShader">验证并保存</button><p class="hint">提供 u_texture、u_time、u_progress、u_resolution。渲染在本机 Chrome WebGL 沙箱中执行。</p>';$('#saveShader').onclick=()=>{let uniforms;try{uniforms=JSON.parse($('#shaderUniforms').value)}catch(e){$('#error').textContent='Uniforms JSON: '+e.message;return}edit({kind:'shader-effect',itemId:f.item.id,name:$('#shaderName').value,source:$('#shaderSource').value,uniforms})}}
function renderJsxMg(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem(),mg=f?.asset?.motionGraphic;if(!mg){p.innerHTML='<p class="hint">请先选择 JSX Motion Graphic。</p>';return}p.innerHTML='<h3>JSX / React MG</h3><label class="field">Props JSON<textarea id="jsxProps" style="width:100%;height:90px;background:#0f1115;color:white">'+esc(JSON.stringify(mg.props||{},null,2))+'</textarea></label><label class="field">组件源码<textarea id="jsxSource" spellcheck="false" style="width:100%;height:290px;background:#0f1115;color:#a8d8ff;font:11px monospace">'+esc(mg.source)+'</textarea></label><button class="save" id="saveJsx">重新渲染透明 MG</button><p class="hint">MotionGraphic 会收到 frame、fps、durationInFrames、progress、width、height 和 Props。保存可能需要逐帧渲染。</p>';$('#saveJsx').onclick=()=>{let props;try{props=JSON.parse($('#jsxProps').value)}catch(e){$('#error').textContent='Props JSON: '+e.message;return}edit({kind:'jsx-mg',assetId:f.asset.id,source:$('#jsxSource').value,props})}}
function renderCaptions(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),captions=state.timeline.captions||{enabled:false,cues:[],style:{}},s=captions.style||{};p.innerHTML='<h3>字幕互操作 · '+captions.cues.length+'</h3><label class="field">导入本地字幕路径<input id="subtitleInput" placeholder="/absolute/path/captions.srt"></label><div class="row"><label class="field">格式<select id="subtitleImportFormat"><option>srt</option><option>vtt</option><option>ass</option></select></label>'+field('subtitleOffset','时间偏移秒',0)+'</div><button class="action" id="importSubtitle">导入并替换字幕</button><div class="row"><label class="field">模板<select id="capTemplate">'+['classic','bold-box','karaoke','minimal'].map(v=>'<option '+((s.template||'classic')===v?'selected':'')+'>'+v+'</option>').join('')+'</select></label><label class="field">位置<select id="capPosition">'+['top','center','bottom'].map(v=>'<option '+((s.position||'bottom')===v?'selected':'')+'>'+v+'</option>').join('')+'</select></label></div><div class="row">'+field('capSize','主字幕字号',s.fontSize||52)+field('capSecondarySize','译文字幕字号',s.secondaryFontSize||34)+'</div><div class="row"><label class="field">主字幕色<input id="capColor" type="color" value="'+esc(s.color||'#ffffff')+'"></label><label class="field">译文颜色<input id="capSecondaryColor" type="color" value="'+esc(s.secondaryColor||'#dbeafe')+'"></label></div><div class="row">'+field('capMargin','边距',s.margin||70)+field('capBgOpacity','背景透明度',s.backgroundOpacity??0)+'</div><label class="field"><input id="capBilingual" type="checkbox" '+(s.bilingual!==false?'checked':'')+'> 显示双语字幕</label><label class="field"><input id="capKaraoke" type="checkbox" '+(s.karaoke?'checked':'')+'> 逐词卡拉 OK</label><button class="save" id="saveCaptionStyle">保存字幕样式</button><h3 style="margin-top:18px">字幕文件导出</h3><label class="field">输出路径<input id="subtitleOutput" placeholder="/absolute/path/captions.vtt"></label><div class="row"><label class="field">格式<select id="subtitleExportFormat"><option>srt</option><option>vtt</option><option>ass</option></select></label><label class="field">内容<select id="subtitleVariant"><option value="original">原文</option><option value="translation">译文</option><option value="bilingual">双语</option></select></label></div><button class="action" id="exportSubtitle">导出字幕文件</button>'+captions.cues.map((c,i)=>'<div class="caption"><small>'+fmt(c.start)+'–'+fmt(c.end)+'</small><input data-caption="'+i+'" value="'+esc(c.text)+'"><input data-translation="'+i+'" placeholder="对应译文" value="'+esc(c.translation||'')+'"></div>').join('');$('#importSubtitle').onclick=()=>edit({kind:'subtitle-import',inputPath:$('#subtitleInput').value,format:$('#subtitleImportFormat').value,offset:+$('#f-subtitleOffset').value});$('#exportSubtitle').onclick=()=>edit({kind:'subtitle-export',outputPath:$('#subtitleOutput').value,format:$('#subtitleExportFormat').value,variant:$('#subtitleVariant').value});document.querySelectorAll('[data-caption]').forEach(input=>input.onchange=()=>edit({kind:'caption',index:+input.dataset.caption,patch:{text:input.value}}));document.querySelectorAll('[data-translation]').forEach(input=>input.onchange=()=>edit({kind:'caption',index:+input.dataset.translation,patch:{translation:input.value}}));$('#saveCaptionStyle').onclick=()=>edit({kind:'caption-style',style:{template:$('#capTemplate').value,position:$('#capPosition').value,fontSize:+$('#f-capSize').value,secondaryFontSize:+$('#f-capSecondarySize').value,margin:+$('#f-capMargin').value,color:$('#capColor').value,secondaryColor:$('#capSecondaryColor').value,backgroundOpacity:+$('#f-capBgOpacity').value,bilingual:$('#capBilingual').checked,karaoke:$('#capKaraoke').checked}})}
function renderPlayback(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f){p.innerHTML='<p class="hint">请先选择片段。</p>';return}const item=f.item,curve=item.speedCurve||[],points=curve.map(x=>(10+280*x.time/Math.max(.01,item.duration))+','+(95-80*(x.rate-.1)/15.9)).join(' ');p.innerHTML='<h3>时间重映射</h3>'+field('playbackRate','基础倍率',item.playbackRate||1)+'<svg viewBox="0 0 300 110" style="width:100%;height:110px;background:#0c0e12;border:1px solid #2b2e36"><path d="M10 95H290M10 15V95" stroke="#343944"/><polyline points="'+points+'" fill="none" stroke="#4f8cff" stroke-width="3"/></svg><label class="field">速度点（每行：时间,倍率,缓动）<textarea id="speedCurve" style="width:100%;height:110px;margin-top:5px;background:#0f1115;color:#fff;border:1px solid #2b2e36;padding:8px">'+curve.map(x=>x.time+','+x.rate+','+(x.easing||'linear')).join('\\n')+'</textarea></label><div class="row"><button class="action" id="curveMontage">蒙太奇预设</button><button class="action" id="curveHero">英雄时刻预设</button></div><label class="field"><input id="reversePlayback" type="checkbox" '+(item.reverse?'checked':'')+'> 倒放素材范围</label><label class="field"><input id="freezeFrame" type="checkbox" '+(item.freezeFrame?'checked':'')+' '+(f.track.type==='audio'?'disabled':'')+'> 定格在素材入点</label><p class="hint">曲线按时间线时间定义；视频逐帧映射，音频分段保调并保持同步。留空即使用固定倍率。</p><button class="save" id="savePlayback">保存速度</button>';const preset=(values)=>{$('#speedCurve').value=values.map(x=>x.join(',')).join('\\n')};$('#curveMontage').onclick=()=>preset([[0,1,'ease-in-out'],[item.duration*.25,3,'ease-out'],[item.duration*.6,.5,'ease-in-out'],[item.duration,1,'linear']]);$('#curveHero').onclick=()=>preset([[0,1,'ease-in-out'],[item.duration*.35,.35,'ease-in-out'],[item.duration*.65,.35,'ease-out'],[item.duration,1.5,'linear']]);$('#savePlayback').onclick=()=>{const speedCurve=$('#speedCurve').value.trim()?$('#speedCurve').value.trim().split(/\\n+/).map(line=>{const [time,rate,easing='linear']=line.split(',').map(x=>x.trim());return{time:+time,rate:+rate,easing}}):[];return edit({kind:'playback',itemId:item.id,playbackRate:+$('#f-playbackRate').value,speedCurve,reverse:$('#reversePlayback').checked,freezeFrame:$('#freezeFrame').checked})}}
function renderEffects(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f){p.innerHTML='<p class="hint">请先选择视频片段。</p>';return}const item=f.item,effects=(item.effects||[]).filter(x=>x.type!=='glsl');p.innerHTML='<h3>非破坏性画面效果</h3><label class="field">效果栈 JSON（按顺序执行）<textarea id="effectStack" style="width:100%;height:220px;margin-top:5px;background:#0f1115;color:#fff;border:1px solid #2b2e36;padding:8px">'+esc(JSON.stringify(effects,null,2))+'</textarea></label><div class="row"><button class="action" id="greenPreset">绿幕抠像</button><button class="action" id="portraitMask">椭圆遮罩</button></div><div class="row"><button class="action" id="cinemaGrade">电影调色</button><button class="action" id="vintageGrade">复古曲线</button></div><p class="hint">支持 chroma-key、mask、color-grade、curves、vignette，以及原有 color/blur/zoom/LUT。GLSL 在独立标签编辑且会保留。</p><button class="save" id="saveEffects">保存效果栈</button>';const set=x=>$('#effectStack').value=JSON.stringify(x,null,2);$('#greenPreset').onclick=()=>set([{type:'chroma-key',color:'#00ff00',similarity:.12,blend:.08}]);$('#portraitMask').onclick=()=>set([{type:'mask',shape:'ellipse',x:40,y:20,width:220,height:260,feather:24,invert:false}]);$('#cinemaGrade').onclick=()=>set([{type:'color-grade',exposure:.12,contrast:1.12,saturation:.92,temperature:.16,tint:.04,redShadows:-.05,blueShadows:.08,redHighlights:.08,blueHighlights:-.05,preserveLightness:true},{type:'vignette',angle:.55,softness:.65}]);$('#vintageGrade').onclick=()=>set([{type:'curves',preset:'vintage'},{type:'vignette',angle:.62,softness:.55}]);$('#saveEffects').onclick=()=>{let effects;try{effects=JSON.parse($('#effectStack').value)}catch(e){$('#error').textContent=e.message;return}const glsl=(item.effects||[]).filter(x=>x.type==='glsl');return edit({kind:'effects',itemId:item.id,effects:[...effects,...glsl]})}}
function renderAudio(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),f=findItem();if(!f||f.track.type!=='audio'){p.innerHTML='<p class="hint">请先选择音频轨道上的片段。</p>';return}const item=f.item,effects=item.audioEffects||[];p.innerHTML='<h3>音频效果链</h3><label class="field">效果栈 JSON（按顺序执行）<textarea id="audioStack" style="width:100%;height:235px;margin-top:5px;background:#0f1115;color:#fff;border:1px solid #2b2e36;padding:8px">'+esc(JSON.stringify(effects,null,2))+'</textarea></label><div class="row"><button class="action" id="voiceClean">人声清理</button><button class="action" id="broadcastVoice">广播人声</button></div><div class="row"><button class="action" id="musicWide">音乐拓宽</button><button class="action" id="pitchDown">低沉音高</button></div><p class="hint">支持 highpass、lowpass、多段 equalizer、compressor、gate、deesser、stereo、pitch 和 limiter。音高变化保持时间线时长。</p><button class="save" id="saveAudio">保存音频效果</button>';const set=x=>$('#audioStack').value=JSON.stringify(x,null,2);$('#voiceClean').onclick=()=>set([{type:'highpass',frequency:75},{type:'gate',thresholdDb:-46,reductionDb:-36,ratio:6,attackMs:5,releaseMs:160},{type:'deesser',intensity:.45,maxReduction:.5,frequency:.58}]);$('#broadcastVoice').onclick=()=>set([{type:'highpass',frequency:70},{type:'equalizer',bands:[{frequency:180,gainDb:-2,q:1},{frequency:3200,gainDb:2.5,q:.9}]},{type:'compressor',thresholdDb:-20,ratio:3.5,attackMs:12,releaseMs:170,makeupDb:3,knee:3,mix:1},{type:'deesser',intensity:.4,maxReduction:.45,frequency:.6},{type:'limiter',ceilingDb:-1}]);$('#musicWide').onclick=()=>set([{type:'stereo',balance:0,width:.45,softClip:true,phaseLeft:false,phaseRight:false},{type:'limiter',ceilingDb:-1}]);$('#pitchDown').onclick=()=>set([{type:'pitch',semitones:-3},{type:'compressor',thresholdDb:-18,ratio:2.5,attackMs:18,releaseMs:200,makeupDb:2,knee:2.8,mix:1}]);$('#saveAudio').onclick=()=>{let audioEffects;try{audioEffects=JSON.parse($('#audioStack').value)}catch(e){$('#error').textContent=e.message;return}return edit({kind:'audio-effects',itemId:item.id,audioEffects})}}
function renderPanel(){document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel');if(tab==='captions'){p.innerHTML='<h3>字幕 '+state.timeline.captions.cues.length+'</h3>'+state.timeline.captions.cues.map((c,i)=>'<div class="caption"><small>'+fmt(c.start)+'–'+fmt(c.end)+'</small><input data-caption="'+i+'" value="'+esc(c.text)+'"></div>').join('');document.querySelectorAll('[data-caption]').forEach(input=>input.onchange=()=>edit({kind:'caption',index:+input.dataset.caption,patch:{text:input.value}}));return}const f=findItem();if(!f){p.innerHTML='<p class="hint">选择片段后可分割、修剪、Ripple 删除、设置转场或编辑 MG。所有写入都会先创建快照。</p>';return}const {item,asset}=f;if(tab==='mg'){if(asset?.motionGraphic?.engine!=='svg'){p.innerHTML='<p class="hint">当前片段不是可编辑 SVG Motion Graphic。</p>';return}const vals=asset.motionGraphic.values||{};p.innerHTML='<h3>'+esc(asset.name)+'</h3>'+asset.motionGraphic.properties.map(x=>'<label class="field">'+esc(x.label)+'<input data-prop="'+esc(x.key)+'" value="'+esc(vals[x.key]??x.defaultValue)+'"></label>').join('')+'<button class="save" id="saveMg">更新 MG</button>';$('#saveMg').onclick=()=>{const values={};document.querySelectorAll('[data-prop]').forEach(i=>values[i.dataset.prop]=i.value);edit({kind:'mg-values',assetId:asset.id,values})};return}const tr=item.transitionOut||{type:'none',duration:.35};p.innerHTML='<h3>'+esc(item.label||asset?.name)+(item.linkGroupId?' <span class="pill">🔗 已链接</span>':'')+'</h3>'+field('label','名称',item.label||'','text')+field('start','时间线位置',item.start)+field('duration','片段长度',item.duration)+field('sourceStart','素材入点',item.sourceStart)+field('opacity','透明度',item.opacity??1)+'<button class="save" id="saveItem">保存片段</button>'+(item.linkGroupId?'<button class="action" id="unlinkGroup">解除音画链接</button>':'')+'<div class="row"><button class="action" id="splitItem">按播放头分割</button><button class="action danger" id="rippleDelete">Ripple 删除</button></div><label class="field">出场转场<select id="transitionType"><option value="none">无</option><option value="fade">淡出</option><option value="dip-black">黑场</option><option value="cross-dissolve">交叉溶解</option><option value="wipe-left">向左擦除</option><option value="wipe-right">向右擦除</option><option value="wipe-up">向上擦除</option><option value="wipe-down">向下擦除</option><option value="radial">径向揭示</option><option value="slide-left">向左滑入</option><option value="slide-right">向右滑入</option><option value="slide-up">向上滑入</option><option value="slide-down">向下滑入</option></select></label>'+field('transitionDuration','转场时长',tr.duration)+'<button class="action" id="saveTransition">保存转场</button><p class="hint">链接片段会成组拖动和修剪；解除链接后才可独立调整。</p>';$('#transitionType').value=tr.type;$('#saveItem').onclick=()=>item.linkGroupId?edit({kind:'linked-move',itemOrGroupId:item.id,start:+$('#f-start').value}):edit({kind:'item',itemId:item.id,patch:{label:$('#f-label').value,start:+$('#f-start').value,duration:+$('#f-duration').value,sourceStart:+$('#f-sourceStart').value,opacity:+$('#f-opacity').value}});$('#unlinkGroup')?.addEventListener('click',()=>edit({kind:'linked-unlink',itemOrGroupId:item.id}));$('#splitItem').onclick=()=>edit({kind:'split',itemId:item.id,at:$('#preview').currentTime});$('#rippleDelete').onclick=()=>edit({kind:'ripple-delete',itemId:item.id,scope:'all'}).then(ok=>{if(ok)selected=null});$('#saveTransition').onclick=()=>edit({kind:'transition',itemId:item.id,edge:'out',type:$('#transitionType').value,duration:+$('#f-transitionDuration').value})}
function startMove(e){if(e.target.dataset.edge)return;const f=findById(e.currentTarget.dataset.id);if(!f||f.track.locked)return;selected=f.item.id;gesture={kind:'move',x:e.clientX,start:f.item.start,el:e.currentTarget};gesture.el.setPointerCapture(e.pointerId);gesture.el.onpointermove=moveGesture;gesture.el.onpointerup=endGesture}
function startTrim(e){e.stopPropagation();const clip=e.currentTarget.parentElement,f=findById(clip.dataset.id);if(!f||f.track.locked)return;selected=f.item.id;gesture={kind:'trim',edge:e.currentTarget.dataset.edge,x:e.clientX,start:f.item.start,end:f.item.start+f.item.duration,el:clip};clip.setPointerCapture(e.pointerId);clip.onpointermove=moveGesture;clip.onpointerup=endGesture}
function moveGesture(e){if(!gesture)return;const delta=(e.clientX-gesture.x)/pps;if(gesture.kind==='move'){gesture.next=Math.max(0,gesture.start+delta);gesture.el.style.left=(gesture.next*pps)+'px'}else if(gesture.edge==='left'){gesture.next=Math.min(gesture.end-.05,Math.max(gesture.start,gesture.start+delta));gesture.el.style.left=(gesture.next*pps)+'px';gesture.el.style.width=Math.max(8,(gesture.end-gesture.next)*pps)+'px'}else{gesture.next=Math.max(gesture.start+.05,Math.min(gesture.end,gesture.end+delta));gesture.el.style.width=Math.max(8,(gesture.next-gesture.start)*pps)+'px'}}
async function endGesture(){if(!gesture)return;const g=gesture;gesture=null;if(g.next===undefined)return renderTimeline();const playhead=$('#preview').currentTime||0,item=findById(selected)?.item;if(item?.linkGroupId){if(g.kind==='move')await edit({kind:'linked-move',itemOrGroupId:selected,start:+g.next.toFixed(3)});else if(g.edge==='left')await edit({kind:'linked-trim',itemOrGroupId:selected,newStart:+g.next.toFixed(3)});else await edit({kind:'linked-trim',itemOrGroupId:selected,newEnd:+g.next.toFixed(3)})}else if(g.kind==='move')await edit({kind:'item',itemId:selected,patch:{start:+g.next.toFixed(3)},snap:true,playhead});else if(g.edge==='left')await edit({kind:'trim',itemId:selected,newStart:+g.next.toFixed(3),playhead});else await edit({kind:'trim',itemId:selected,newEnd:+g.next.toFixed(3),playhead})}
function syncPlayhead(){const v=$('#preview'),t=v.currentTime||0;$('#playhead').style.left=(118+t*pps)+'px';$('#clock').textContent=fmt(t)}
document.querySelectorAll('[data-video-type]').forEach(button=>button.onclick=()=>showVideoSetup(button.dataset.videoType,button.querySelector('strong').textContent));$('#typeBack').onclick=showTypeStep;$('#vlogForm').onsubmit=async e=>{e.preventDefault();const button=e.currentTarget.querySelector('[type="submit"]');button.disabled=true;button.textContent='正在准备';$('#onboardError').textContent='';const ok=await edit({kind:'select-video-type',typeId:selectedVideoType,setup:{style:$('#vlogStyle').value,format:$('#vlogFormat').value,pace:$('#vlogPace').value,targetDuration:+$('#vlogDuration').value,narration:$('#vlogNarration').value,musicMood:$('#vlogMusic').value,objective:$('#vlogObjective').value,notes:$('#vlogNotes').value}});button.disabled=false;button.textContent='开始项目';if(!ok)$('#onboardError').textContent=$('#error').textContent};
$('#preview').ontimeupdate=syncPlayhead;$('#play').onclick=()=>{const v=$('#preview');if(v.paused)v.play().catch(e=>$('#error').textContent=e.message);else v.pause()};$('#selectionMode').onclick=()=>{selectionMode=!selectionMode;render()};$('#clearContext').onclick=()=>edit({kind:'context-clear'});$('#canvas').onclick=e=>{if(!selectionMode||e.target.closest('.clip')||e.target.closest('.track-name'))return;const rect=$('#canvas').getBoundingClientRect(),time=Math.max(0,Math.min(state.duration,(e.clientX-rect.left-118)/pps));edit({kind:'context-add',reference:{type:'time',timelineId:state.timeline.id,time:+time.toFixed(3)}})};$('#undo').onclick=()=>edit({kind:'undo'});$('#redo').onclick=()=>edit({kind:'redo'});$('#timelineSelect').onchange=e=>{selected=null;edit({kind:'activate-timeline',timelineId:e.target.value})};$('#snapping').onclick=()=>edit({kind:'snapping',enabled:state.timeline.settings?.snapping?.enabled===false});$('#aspect').onchange=e=>edit({kind:'timeline-format',timelineId:state.timeline.id,preset:e.target.value,layoutMode:'scale'});$('#setZone').onclick=()=>edit({kind:'timeline-in-out',timelineId:state.timeline.id,inPoint:+$('#inPoint').value,outPoint:+$('#outPoint').value});$('#clearZone').onclick=()=>edit({kind:'timeline-in-out',timelineId:state.timeline.id,inPoint:null,outPoint:null});$('#zoom').oninput=e=>{pps=+e.target.value;renderTimeline()};$('#razor').onclick=()=>edit({kind:'razor-all',at:$('#preview').currentTime});$('#insertGap').onclick=()=>edit({kind:'insert-gap',at:$('#preview').currentTime,duration:+$('#gapDuration').value,scope:'all'});document.querySelectorAll('.tabs button').forEach(b=>b.onclick=()=>{tab=b.dataset.tab;renderPanel()});load().catch(e=>$('#error').textContent=e.message);
document.querySelector('[data-tab="keyframes"]').onclick=()=>{tab='keyframes';renderKeyframes()};
document.querySelector('[data-tab="shader"]').onclick=()=>{tab='shader';renderShader()};
document.querySelector('[data-tab="mg"]').onclick=()=>{tab='mg';findItem()?.asset?.motionGraphic?.engine==='jsx-react'?renderJsxMg():renderPanel()};
document.querySelector('[data-tab="captions"]').onclick=()=>{tab='captions';renderCaptions()};
document.querySelector('[data-tab="playback"]').onclick=()=>{tab='playback';renderPlayback()};
document.querySelector('[data-tab="effects"]').onclick=()=>{tab='effects';renderEffects()};
document.querySelector('[data-tab="audio"]').onclick=()=>{tab='audio';renderAudio()};
document.querySelector('[data-tab="transcript"]').onclick=()=>{tab='transcript';renderTranscript()};
document.querySelector('[data-tab="source"]').onclick=()=>{tab='source';renderSource()};
