const vlogPanelObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const bind=(selector,handler)=>{const element=$(selector);if(element)element.onclick=handler};bind('#analyzeVlog',()=>edit({kind:'vlog-coverage'}));bind('#planVlog',()=>edit({kind:'vlog-plan',options:{targetDuration:+$('#f-vlogDuration').value,pace:$('#vlogPace').value}}));bind('#applyVlog',()=>edit({kind:'vlog-apply',plan:state.vlogPlan,options:{trackName:'V1 · Story',replace:true}}));bind('#planVlogBroll',()=>edit({kind:'vlog-broll-plan',options:{maxShotDuration:+$('#f-brollMax').value,coverage:+$('#f-brollCoverage').value}}));bind('#applyVlogBroll',()=>edit({kind:'vlog-broll-apply',plan:state.vlogBrollPlan,options:{trackName:'V2 · Cutaways',replace:true}}))});vlogPanelObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogStory();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),audit=state.vlogRhythmAudit,rhythmPlan=state.vlogRhythmPlan;p.innerHTML+='<h3 style="margin-top:22px">自动节奏导演</h3><p class="hint">检查长口播、长镜头、重复画面、配画空档和音频 Ducking。安全修改可自动应用，删句和补拍保留人工决定。</p><div class="row">'+field('rhythmTalk','最长连续口播',state.project.videoType.vlog.pace==='energetic'?4:6)+field('rhythmGap','配画空档阈值',6)+'</div><button class="action" id="analyzeVlogRhythm">检查当前节奏</button>'+(audit?'<div class="caption"><b>节奏评分 '+audit.score+'/100</b><small>长镜头 '+audit.counts.longShots+' · 重复画面 '+audit.counts.repeatedShots+' · 长口播 '+audit.counts.talkingHeadRuns+' · 配画空档 '+audit.counts.visualGaps+'</small></div>'+audit.suggestions.slice(0,8).map(x=>'<div class="caption"><b>'+fmt(x.start)+'–'+fmt(x.end)+'</b><small>'+esc(x.suggestion)+'</small></div>').join('')+'<button class="action" id="planVlogRhythm">生成安全节奏优化方案</button>':'')+(rhythmPlan?'<div class="caption"><b>安全修改 '+rhythmPlan.summary.safeChanges+' 项</b><small>人工决定 '+rhythmPlan.summary.manualDecisions+' 项 · '+(rhythmPlan.summary.duckingConfigured?'已配置人声压音乐':'缺少完整人声/音乐轨')+'</small></div><p class="hint">将加入配画预入场、短交叉过渡、音频淡入淡出、人声 anchor 与音乐 follower。不会自动删除口播。</p><button class="save" id="applyVlogRhythm">确认应用节奏优化</button>':'');$('#analyzeVlogRhythm').onclick=()=>edit({kind:'vlog-rhythm-analyze',options:{maxTalkingHeadSeconds:+$('#f-rhythmTalk').value,gapWindowSeconds:+$('#f-rhythmGap').value}});if(audit)$('#planVlogRhythm').onclick=()=>edit({kind:'vlog-rhythm-plan',options:{maxTalkingHeadSeconds:+$('#f-rhythmTalk').value,gapWindowSeconds:+$('#f-rhythmGap').value}});if(rhythmPlan)$('#applyVlogRhythm').onclick=()=>edit({kind:'vlog-rhythm-apply',plan:rhythmPlan})};
const renderVlogRhythm=renderVlog;
const vlogDirectorObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const bind=(selector,handler)=>{const element=$(selector);if(element)element.onclick=handler};bind('#analyzeVlogRhythm',()=>edit({kind:'vlog-rhythm-analyze',options:{maxTalkingHeadSeconds:+$('#f-rhythmTalk').value,gapWindowSeconds:+$('#f-rhythmGap').value}}));bind('#planVlogRhythm',()=>edit({kind:'vlog-rhythm-plan',options:{maxTalkingHeadSeconds:+$('#f-rhythmTalk').value,gapWindowSeconds:+$('#f-rhythmGap').value}}));bind('#applyVlogRhythm',()=>edit({kind:'vlog-rhythm-apply',plan:state.vlogRhythmPlan}));bind('#planVlogSound',()=>edit({kind:'vlog-sound-plan',options:{musicVolumeDb:+$('#f-soundMusic').value,ambienceVolumeDb:+$('#f-soundAmbience').value,sfxVolumeDb:+$('#f-soundSfx').value,naturalSound:true}}));bind('#applyVlogSound',()=>edit({kind:'vlog-sound-apply',plan:state.vlogSoundPlan,options:{replace:true}}))});vlogDirectorObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogRhythm();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),sound=state.vlogSoundPlan;p.innerHTML+='<h3 style="margin-top:22px">Vlog 声音导演</h3><p class="hint">用明确标注的音乐和音效素材，并从含音轨的配画中提取环境声。缺少素材会报告，不会用普通音频冒充。</p><div class="row">'+field('soundMusic','音乐基础 dB',-17)+field('soundAmbience','环境声 dB',-20)+'</div>'+field('soundSfx','音效 dB',-10)+'<button class="action" id="planVlogSound">生成可审阅声音方案</button>'+(sound?'<div class="caption"><b>声音方案：音乐 '+sound.summary.musicSegments+' 段</b><small>环境声 '+sound.summary.ambienceMoments+' · 音效 '+sound.summary.effects+' · 警告 '+sound.summary.warnings+'</small></div>'+sound.warnings.map(x=>'<div class="caption"><b>素材缺口</b><small>'+esc(x.message)+'</small></div>').join('')+'<p class="hint">音乐按开场、主体、高潮、结尾分段控制；人声保持 Anchor，音乐作为 Follower 自动 Ducking。</p><button class="save" id="applyVlogSound">确认写入声音轨</button>':'')};
