const vlogFinishingObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const bind=(selector,handler)=>{const element=$(selector);if(element)element.onclick=handler};bind('#planVlogFinishing',()=>edit({kind:'vlog-finishing-plan',options:{openingTitle:$('#finishingTitle').value,cta:$('#finishingCta').value,platform:$('#finishingPlatform').value,bilingual:$('#finishingBilingual').checked}}));bind('#applyVlogFinishing',()=>edit({kind:'vlog-finishing-apply',plan:state.vlogFinishingPlan}))});vlogFinishingObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogSound();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),finish=state.vlogFinishingPlan,brief=state.project.videoType.vlog;p.innerHTML+='<h3 style="margin-top:22px">Vlog 成片导演</h3><p class="hint">检查字幕阅读速度、安全区和发布规格；生成开场、地点和结尾 CTA 的可编辑 MG 规格，并先加入包装清单。</p><label class="field">开场标题<input id="finishingTitle" value="'+esc(brief.objective||state.project.name)+'"></label><label class="field">结尾 CTA<input id="finishingCta" value="关注我，继续记录"></label><label class="field">发布平台<select id="finishingPlatform"><option value="short-video">短视频平台</option><option value="youtube">YouTube</option><option value="instagram">Instagram</option><option value="custom">自定义</option></select></label><label class="field"><input id="finishingBilingual" type="checkbox"> 双语字幕安全样式</label><button class="action" id="planVlogFinishing">生成成片包装方案</button>'+(finish?'<div class="caption"><b>包装：'+finish.summary.titleCards+' 张标题卡 · '+finish.summary.markers+' 个标记</b><small>字幕问题 '+finish.summary.captionIssues+' · 警告 '+finish.summary.warnings+' · '+finish.exportPreset.aspect+' '+finish.exportPreset.width+'×'+finish.exportPreset.height+'</small></div>'+finish.titleCards.map(x=>'<div class="caption"><b>'+fmt(x.start)+' '+esc(x.title)+'</b><small>'+esc(x.kind)+' · '+x.duration.toFixed(1)+'s · '+esc(x.placement)+'</small></div>').join('')+finish.captionIssues.slice(0,6).map(x=>'<div class="caption"><b>字幕 '+fmt(x.start)+'</b><small>'+esc(x.suggestion)+'</small></div>').join('')+'<p class="hint">确认后写入字幕样式、安全区、章节标记和发布预设；标题卡作为可编辑 MG 规格进入 V3 待渲染清单。</p><button class="save" id="applyVlogFinishing">确认应用成片包装</button>':'')};
