const vlogTitleObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const button=$('#renderVlogTitles');if(button)button.onclick=()=>edit({kind:'vlog-titles-render',options:{trackName:'V3 · Titles',accent:$('#titleAccent').value,background:'#17150f',textColor:'#ffffff',secondaryColor:'#e4dac7',replace:true}})});vlogTitleObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogFinishing();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),cards=state.timeline.pendingTitleCards||[],rendered=state.renderedVlogTitles;if(!cards.length)return;p.innerHTML+='<h3 style="margin-top:22px">渲染可编辑 MG 标题</h3><p class="hint">使用安全 SVG 模板生成源文件和透明 PNG，并放入 V3。渲染后仍可在 MG 面板修改文字与颜色。</p><label class="field">强调色<input id="titleAccent" type="color" value="#e5484d"></label><button class="save" id="renderVlogTitles">渲染并写入 V3 · Titles</button>'+(rendered?'<div class="caption"><b>已渲染 '+rendered.filter(x=>!x.skipped).length+' 张</b><small>跳过 '+rendered.filter(x=>x.skipped).length+' 张时间冲突卡片</small></div>':'')};
