const vlogReleaseObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const analyze=$('#analyzeVlogRelease'),fix=$('#fixVlogRelease');if(analyze)analyze.onclick=()=>edit({kind:'vlog-release-analyze',options:{requireCaptions:true,maxVideoGap:.25}});if(fix)fix.onclick=()=>edit({kind:'vlog-release-fix',preflight:state.vlogReleasePreflight})});vlogReleaseObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogTitles();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),release=state.vlogReleasePreflight;p.innerHTML+='<h3 style="margin-top:22px">发布前总检</h3><p class="hint">统一检查离线素材、主画面空档、字幕、标题、声音结构、安全区、时长和发布预设。阻断项清零才会显示可发布。</p><button class="action" id="analyzeVlogRelease">运行严格发布总检</button>'+(release?'<div class="caption"><b>'+(release.ready?'可以发布':'暂不可发布')+' · '+release.score+'/100</b><small>阻断 '+release.blockers.length+' · 警告 '+release.warnings.length+' · 可自动修复 '+release.safeFixes.length+'</small></div>'+release.blockers.map(x=>'<div class="caption"><b>阻断 · '+esc(x.kind)+'</b><small>'+esc(x.message)+'</small></div>').join('')+release.warnings.slice(0,8).map(x=>'<div class="caption"><b>警告 · '+esc(x.kind)+'</b><small>'+esc(x.message)+'</small></div>').join('')+release.safeFixes.map(x=>'<div class="caption"><b>安全修复</b><small>'+esc(x.message)+'</small></div>').join('')+(release.safeFixes.length?'<button class="save" id="fixVlogRelease">应用安全修复并重新检查</button>':''):'')};
