const vlogWorkflowObserver=new MutationObserver(()=>{if(tab!=='vlog')return;const refresh=$('#refreshVlogWorkflow'),submit=$('#submitVlogRelease');if(refresh)refresh.onclick=()=>edit({kind:'vlog-workflow-status'});if(submit)submit.onclick=()=>edit({kind:'vlog-release-export',name:$('#vlogReleaseName')?.value||state.project.name+'-release'})});vlogWorkflowObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderVlogRelease();if(state.project.videoType?.id!=='vlog')return;const p=$('#panel'),workflow=state.vlogWorkflowStatus;p.innerHTML+='<h3 style="margin-top:22px">Vlog 制作进度</h3><p class="hint">每一步都读取项目中的真实证据。按钮点过但内容没有写入时间线，不会算完成。</p><button class="action" id="refreshVlogWorkflow">刷新真实工作流状态</button>'+(workflow?'<div class="caption"><b>'+workflow.completed+'/'+workflow.total+' · '+workflow.progress+'%</b><small>'+(workflow.readyToExport?'全部阶段完成，可以发布':'导出锁定：还有 '+(workflow.total-workflow.completed)+' 个阶段未完成')+'</small></div>'+workflow.stages.map(x=>'<div class="caption"><b>'+(x.complete?'✓':'○')+' '+esc(x.label)+'</b><small>'+esc(x.detail)+'</small></div>').join('')+'<div class="caption"><b>下一步 · '+esc(workflow.nextAction.label)+'</b><small>'+esc(workflow.nextAction.instruction)+' · '+esc(workflow.nextAction.tool)+'</small></div>'+(workflow.readyToExport?'<label class="field">发布文件名<input id="vlogReleaseName" value="'+esc(state.project.name)+'-release"></label><button class="save" id="submitVlogRelease">通过总检并提交 MP4</button>':'<p class="hint">导出锁定会在离线素材、空画面、缺字幕或未渲染标题等阻断项清除后自动解除。</p>'):'')};
