const categoryWorkflowObserver=new MutationObserver(()=>{if(tab!=='vlog'||state.project.videoType?.id==='vlog')return;const refresh=$('#refreshCategoryWorkflow'),fix=$('#fixCategoryRelease'),submit=$('#submitCategoryRelease');if(refresh)refresh.onclick=()=>edit({kind:'category-workflow-status'});if(fix)fix.onclick=()=>edit({kind:'category-release-fix',preflight:state.categoryWorkflowStatus.release});if(submit)submit.onclick=()=>edit({kind:'category-release-export',name:$('#categoryReleaseName')?.value||state.project.name+'-release'})});categoryWorkflowObserver.observe($('#panel'),{childList:true,subtree:true});
function renderCategoryDirector(){document.querySelector('[data-tab="vlog"]').textContent='导演';document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));const p=$('#panel'),workflow=state.categoryWorkflowStatus,type=state.project.videoType;p.innerHTML='<h3>'+esc(type?.label||'分类')+' AI 导演</h3><div class="caption"><b>'+esc(type?.details?.style||'自定义风格')+' · '+esc(type?.details?.pace||'balanced')+' · '+(type?.details?.targetDuration||'—')+' 秒</b><small>'+esc(type?.details?.objective||'尚未填写创作目标')+'</small></div><p class="hint">阶段状态来自真实素材、时间线、字幕、音频、MG 和发布设置。没有写入工程的步骤不会被标为完成。</p><button class="action" id="refreshCategoryWorkflow">检查真实制作进度</button>'+(workflow?'<div class="caption"><b>'+workflow.completed+'/'+workflow.total+' · '+workflow.progress+'%</b><small>'+(workflow.readyToExport?'已经通过严格总检':'导出锁定：还有 '+(workflow.total-workflow.completed)+' 个阶段未完成')+'</small></div>'+workflow.stages.map(x=>'<div class="caption"><b>'+(x.complete?'✓':'○')+' '+esc(x.label)+'</b><small>'+esc(x.detail)+'</small></div>').join('')+'<div class="caption"><b>下一步 · '+esc(workflow.nextAction.label)+'</b><small>'+esc(workflow.nextAction.instruction)+' · '+esc(workflow.nextAction.tool)+'</small></div>'+workflow.release.blockers.map(x=>'<div class="caption"><b>阻断 · '+esc(x.kind)+'</b><small>'+esc(x.message)+'</small></div>').join('')+workflow.release.safeFixes.map(x=>'<div class="caption"><b>安全修复</b><small>'+esc(x.message)+'</small></div>').join('')+(workflow.release.safeFixes.length?'<button class="action" id="fixCategoryRelease">应用安全修复并复检</button>':'')+(workflow.readyToExport?'<label class="field">发布文件名<input id="categoryReleaseName" value="'+esc(state.project.name)+'-release"></label><button class="save" id="submitCategoryRelease">通过总检并提交 MP4</button>':'<p class="hint">先按“下一步”调用对应 AI 工具，处理完成后刷新状态。</p>'):'')}
