const talkingHeadObserver=new MutationObserver(()=>{if(tab!=='vlog'||state.project.videoType?.id!=='talking-head')return;const plan=$('#planTalkingHead'),apply=$('#applyTalkingHead');if(plan)plan.onclick=()=>edit({kind:'talking-head-plan',options:{assetId:$('#talkingHeadAsset').value,removeFillerOnly:$('#talkingHeadFillers').checked,maxBrollSeconds:+$('#f-talkingHeadBroll').value,brollCoverage:.75}});if(apply)apply.onclick=()=>edit({kind:'talking-head-apply',plan:state.talkingHeadPlan,options:{videoTrackName:'V1 · Speaker',audioTrackName:'A1 · Dialogue',brollTrackName:'V2 · B-roll'}})});talkingHeadObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderCategoryBase();if(state.project.videoType?.id!=='talking-head')return;const p=$('#panel'),plan=state.talkingHeadPlan,sources=state.project.assets.filter(x=>x.type==='video'&&x.hasAudio&&x.transcript?.cues?.length);p.innerHTML+='<h3 style="margin-top:22px">口播一键导演</h3><p class="hint">从已转录主素材生成可审阅文字初剪。只自动移除独立成句的明确填充词，不擅自删除观点；同时按语义规划 B-roll 和人声清理。</p><label class="field">已转录主素材<select id="talkingHeadAsset">'+sources.map(x=>'<option value="'+x.id+'">'+esc(x.name)+' · '+x.transcript.cues.length+' 段</option>').join('')+'</select></label><label class="field"><input id="talkingHeadFillers" type="checkbox" checked> 移除独立填充词段（Um、Uh、呃、额等）</label>'+field('talkingHeadBroll','最长 B-roll 秒数',4)+'<button class="action" id="planTalkingHead" '+(!sources.length?'disabled':'')+'>生成口播导演方案</button>'+(plan?'<div class="caption"><b>保留 '+plan.summary.keptSegments+'/'+plan.summary.sourceSegments+' 段 · '+plan.summary.estimatedDuration+' 秒</b><small>安全移除填充词 '+plan.summary.removedFillers+' 段 · B-roll '+plan.summary.brollShots+' 个</small></div>'+plan.removedSegments.map(x=>'<div class="caption"><b>拟移除 '+fmt(x.sourceStart)+'</b><small>'+esc(x.text)+' · '+esc(x.reason)+'</small></div>').join('')+plan.broll.map(x=>'<div class="caption"><b>'+fmt(x.start)+' '+esc(x.label)+'</b><small>'+esc(x.cueText)+' · 匹配 '+x.matches.map(esc).join(' / ')+'</small></div>').join('')+'<p class="hint">确认后会先创建快照，再写入说话人音画、B-roll、人声效果、字幕、音乐避让和发布预设。</p><button class="save" id="applyTalkingHead">确认应用口播导演</button>':'')};
const renderTalkingHead=renderVlog;
const explainerObserver=new MutationObserver(()=>{if(tab!=='vlog'||state.project.videoType?.id!=='explainer')return;const plan=$('#planExplainer'),apply=$('#applyExplainer');if(plan)plan.onclick=()=>edit({kind:'explainer-plan',options:{narrationAssetId:$('#explainerNarration').value,maxShotSeconds:+$('#f-explainerShot').value}});if(apply)apply.onclick=()=>edit({kind:'explainer-apply',plan:state.explainerPlan})});explainerObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderTalkingHead();if(state.project.videoType?.id!=='explainer')return;const p=$('#panel'),plan=state.explainerPlan,sources=state.project.assets.filter(x=>x.transcript?.cues?.length&&(x.type==='audio'||x.hasAudio));p.innerHTML+='<h3 style="margin-top:22px">解说视频一键导演</h3><p class="hint">以旁白为时间轴匹配主画面与第二证据来源。数字、步骤和结论会进入待确认信息卡清单，真正渲染前继续锁定导出。</p><label class="field">已转录旁白<select id="explainerNarration">'+sources.map(x=>'<option value="'+x.id+'">'+esc(x.name)+' · '+x.transcript.cues.length+' 段</option>').join('')+'</select></label>'+field('explainerShot','最长单镜头',5)+'<button class="action" id="planExplainer" '+(!sources.length?'disabled':'')+'>生成解说导演方案</button>'+(plan?'<div class="caption"><b>旁白 '+plan.summary.narrationSegments+' 段 · 主画面 '+plan.summary.primaryShots+' · 证据 '+plan.summary.evidenceShots+'</b><small>配画缺口 '+plan.summary.gaps+' · 待制作信息卡 '+plan.summary.infoCards+'</small></div>'+plan.gaps.map(x=>'<div class="caption"><b>缺口 '+fmt(x.start)+'</b><small>'+esc(x.text)+' · '+esc(x.suggestion)+'</small></div>').join('')+plan.infoCards.map(x=>'<div class="caption"><b>信息卡 '+fmt(x.start)+'</b><small>'+esc(x.title)+' · 待确认与渲染</small></div>').join('')+'<button class="save" id="applyExplainer">确认应用解说导演</button>':'')};
