renderVlog=function(){renderExplainerBase();if(state.project.videoType?.id!=='explainer')return;const p=$('#panel'),cards=state.timeline.pendingTitleCards||[],pending=cards.filter(x=>x.status==='pending'),approved=cards.filter(x=>x.status==='approved'),rendered=cards.filter(x=>x.status==='rendered');if(!cards.length)return;p.innerHTML+='<h3 style="margin-top:22px">信息 MG 审核与渲染</h3><p class="hint">先逐条核对下方文字与事实。确认按钮只改变审核状态；第二步才会生成安全 SVG、透明 PNG 和可编辑 MG 素材。</p>'+cards.map(x=>'<div class="caption"><b>'+esc(x.title)+'</b><small>'+esc(x.subtitle||'')+' · '+esc(x.factStatus||x.status)+'</small></div>').join('')+(pending.length?'<label class="field"><input type="checkbox" id="explainerFactsConfirmed" onchange="this.nextElementSibling.disabled=!this.checked"> 我已核对全部文字与事实</label><button class="action" id="reviewExplainerInfo" disabled>确认全部信息卡</button>':'')+(approved.length?'<label class="field">MG 强调色<input id="explainerInfoAccent" type="color" value="#e5484d"></label><button class="save" id="renderExplainerInfo">渲染 '+approved.length+' 张可编辑信息 MG</button>':'')+(rendered.length?'<div class="caption"><b>已渲染 '+rendered.length+' 张信息 MG</b><small>可在时间线 V3 和 MG 面板继续修改</small></div>':'')};
