renderVlog=function(){renderProductBase();if(state.project.videoType?.id!=='product-promo')return;const p=$('#panel'),plan=state.productPromoPlan,cards=state.timeline.pendingTitleCards||[],pending=cards.filter(x=>x.status==='pending'),approved=cards.filter(x=>x.status==='approved'),rendered=cards.filter(x=>x.status==='rendered'),music=state.project.assets.filter(x=>x.type==='audio');p.innerHTML+='<h3 style="margin-top:22px">产品广告一键导演</h3><p class="hint">只使用你填写的卖点和证明，不自动编造广告主张。按 Hook、问题、卖点、证明、CTA 组织 Hero 与细节镜头；音乐有节拍标记时自动对齐。</p><label class="field">产品名称<input id="productName" placeholder="必填"></label><label class="field">Hook<input id="productHook" placeholder="第一眼为什么要停下来"></label><label class="field">用户问题<input id="productProblem" placeholder="产品解决什么问题"></label><label class="field">卖点（每行一个）<textarea id="productBenefits" rows="3" placeholder="必填，最多 5 条"></textarea></label><label class="field">证明 / 依据<input id="productProof" placeholder="测试、数据、演示或用户证据"></label><label class="field">优惠<input id="productOffer" placeholder="可选"></label><label class="field">CTA<input id="productCta" placeholder="必填，例如立即购买"></label>'+field('productDuration','目标秒数',state.project.videoType.details?.targetDuration||30)+'<label class="field">节拍音乐<select id="productMusic"><option value="">不指定</option>'+music.map(x=>'<option value="'+x.id+'">'+esc(x.name)+'</option>').join('')+'</select></label><button class="action" id="planProductPromo">生成广告导演方案</button>'+(plan?'<div class="caption"><b>'+plan.summary.sections+' 段 · Hero '+plan.summary.heroShots+' · 细节 '+plan.summary.detailShots+'</b><small>品牌卡 '+plan.summary.cards+' · 素材缺口 '+plan.summary.gaps+' · '+(plan.beatAligned?'已对齐音乐节拍':'固定时间结构')+'</small></div>'+plan.sections.map(x=>'<div class="caption"><b>'+fmt(x.start)+' '+esc(x.label)+'</b><small>'+esc(x.text)+'</small></div>').join('')+plan.gaps.map(x=>'<div class="caption"><b>素材缺口 · '+esc(x.section)+'</b><small>'+esc(x.suggestion)+'</small></div>').join('')+'<button class="save" id="applyProductPromo">确认应用广告初剪</button>':'')+(cards.length?'<h3 style="margin-top:22px">品牌主张审核</h3>'+cards.map(x=>'<div class="caption"><b>'+esc(x.title)+'</b><small>'+esc(x.subtitle)+' · '+esc(x.factStatus||x.status)+'</small></div>').join('')+(pending.length?'<label class="field"><input type="checkbox" onchange="this.nextElementSibling.disabled=!this.checked"> 我已确认全部卖点、证明和 CTA</label><button class="action" id="reviewProductPromo" disabled>批准品牌主张</button>':'')+(approved.length?'<label class="field">品牌强调色<input id="productAccent" type="color" value="#e5484d"></label><button class="save" id="renderProductPromo">渲染 '+approved.length+' 张品牌 MG</button>':'')+(rendered.length?'<div class="caption"><b>已渲染 '+rendered.length+' 张品牌 MG</b><small>已放入 V3 · Text & CTA，可继续手工调整</small></div>':''):'')};
