renderVlog=function(){renderPodcastBase();if(state.project.videoType?.id!=='podcast')return;const p=$('#panel'),plan=state.podcastPlan,cards=state.timeline.pendingTitleCards||[],pending=cards.filter(x=>x.status==='pending'),approved=cards.filter(x=>x.status==='approved'),rendered=cards.filter(x=>x.status==='rendered'),transcripts=state.project.assets.filter(x=>x.transcript?.cues?.some(c=>c.speaker||c.speakerId)),selected=transcripts[0],speakers=[...new Set((selected?.transcript?.cues||[]).map(c=>String(c.speaker||c.speakerId||'').trim()).filter(Boolean))],cameraIds=state.timeline.multicamSync?.offsets?.map(x=>x.assetId)||[],cameras=cameraIds.map(id=>state.project.assets.find(x=>x.id===id)).filter(Boolean);p.innerHTML+='<h3 style="margin-top:22px">播客 / 访谈一键导演</h3><p class="hint">需要先完成多机位同步，并提供带说话人标签的转录。每位说话人必须人工映射到机位；重叠对话可指定全景机位。不会根据脸或声音猜身份。</p><label class="field">多人转录<select id="podcastTranscript">'+transcripts.map(x=>'<option value="'+x.id+'">'+esc(x.name)+'</option>').join('')+'</select></label>'+speakers.map((speaker,index)=>'<label class="field">'+esc(speaker)+' 显示名<input data-podcast-name="'+esc(speaker)+'" value="'+esc(speaker)+'"></label><label class="field">'+esc(speaker)+' 对应机位<select data-podcast-speaker="'+esc(speaker)+'">'+cameras.map((x,i)=>'<option value="'+x.id+'" '+(i===index?'selected':'')+'>'+esc(x.name)+'</option>').join('')+'</select></label>').join('')+'<label class="field">重叠对话全景<select id="podcastOverlap"><option value="">不指定</option>'+cameras.map(x=>'<option value="'+x.id+'">'+esc(x.name)+'</option>').join('')+'</select></label><label class="field">切机节奏<select id="podcastPace"><option value="balanced">均衡</option><option value="stable">稳定</option><option value="dynamic">动态</option></select></label>'+field('podcastChapter','章节间隔（分钟）',5)+field('podcastClipMin','短视频最短秒数',15)+field('podcastClipMax','短视频最长秒数',60)+field('podcastClips','最多短视频数',3)+'<button class="action" id="planPodcast" '+(!selected||!cameras.length?'disabled':'')+'>生成播客导演方案</button>'+(plan?'<div class="caption"><b>说话人 '+plan.summary.speakers+' · 切机 '+plan.summary.switches+' · 重叠 '+plan.summary.overlaps+'</b><small>章节 '+plan.summary.chapters+' · 短视频 '+plan.summary.clips+' · 嘉宾标题 '+plan.summary.cards+'</small></div>'+plan.chapters.map(x=>'<div class="caption"><b>'+fmt(x.start)+' '+esc(x.title)+'</b><small>'+x.speakers.map(esc).join(' / ')+'</small></div>').join('')+plan.clips.map(x=>'<div class="caption"><b>短视频候选 '+fmt(x.start)+'–'+fmt(x.end)+'</b><small>'+esc(x.title)+' · 评分 '+x.score+'</small></div>').join('')+'<button class="save" id="applyPodcast">确认应用并创建短视频时间线</button>':'')+(cards.length?'<h3 style="margin-top:22px">嘉宾标题审核</h3>'+cards.map(x=>'<div class="caption"><b>'+esc(x.title)+'</b><small>'+esc(x.subtitle)+' · '+esc(x.factStatus||x.status)+'</small></div>').join('')+(pending.length?'<label class="field"><input type="checkbox" onchange="this.nextElementSibling.disabled=!this.checked"> 我已确认主持人与嘉宾身份</label><button class="action" id="reviewPodcastTitles" disabled>批准嘉宾标题</button>':'')+(approved.length?'<label class="field">标题强调色<input id="podcastAccent" type="color" value="#e5484d"></label><button class="save" id="renderPodcastTitles">渲染 '+approved.length+' 张嘉宾 MG</button>':'')+(rendered.length?'<div class="caption"><b>已渲染 '+rendered.length+' 张嘉宾 MG</b><small>短视频候选已作为独立时间线保留</small></div>':''):'')};
