const mgDirectorObserver=new MutationObserver(()=>{if(tab!=='vlog'||state.project.videoType?.id!=='motion-graphics')return;const plan=$('#planMgDirector'),apply=$('#applyMgDirector'),review=$('#reviewMgScenes'),render=$('#renderMgScenes');if(plan)plan.onclick=()=>{const scenes=$('#mgScenes').value.split(/\\n+/).map(line=>{const[kind='title',title='',subtitle='',value='',unit='',duration='3']=line.split('|').map(x=>x.trim());return{kind,title,subtitle,value,unit,duration:+duration}}).filter(x=>x.title);return edit({kind:'mg-director-plan',options:{scenes,musicAssetId:$('#mgMusic').value||undefined,sfxAssetIds:[...document.querySelectorAll('[data-mg-sfx]:checked')].map(x=>x.dataset.mgSfx),accent:$('#mgAccent').value,background:$('#mgBackground').value,pace:$('#mgPace').value}})};if(apply)apply.onclick=()=>edit({kind:'mg-director-apply',plan:state.motionGraphicsPlan});if(review)review.onclick=()=>edit({kind:'mg-scene-review',decisions:(state.timeline.pendingTitleCards||[]).filter(x=>x.status==='pending').map(x=>({id:x.id,action:'approve',title:x.title,subtitle:x.subtitle,note:'已确认 MG 文案与数值'}))});if(render)render.onclick=()=>edit({kind:'mg-scene-render',options:{replace:true}})});mgDirectorObserver.observe($('#panel'),{childList:true,subtree:true});
renderVlog=function(){renderMgBase();if(state.project.videoType?.id!=='motion-graphics')return;const p=$('#panel'),plan=state.motionGraphicsPlan,cards=state.timeline.pendingTitleCards||[],pending=cards.filter(x=>x.status==='pending'),approved=cards.filter(x=>x.status==='approved'),rendered=cards.filter(x=>x.status==='rendered'),audio=state.project.assets.filter(x=>x.type==='audio');p.innerHTML+='<h3 style="margin-top:22px">纯 MG 动画一键导演</h3><p class="hint">每行一个场景，格式：类型 | 标题 | 副标题 | 数值 | 单位 | 秒数。类型支持 title、data、list、cta。系统不会新增或改写文案与数字。</p><label class="field">MG 场景<textarea id="mgScenes" rows="7" placeholder="title | CutPilot | AI video editing | | | 3\\ndata | Tools | Editable workflows | 178 | + | 3\\ncta | Start creating | Keep timeline control | | | 3"></textarea></label><label class="field">节奏<select id="mgPace"><option value="balanced">均衡</option><option value="energetic">快速</option><option value="calm">舒缓</option></select></label><label class="field">强调色<input id="mgAccent" type="color" value="#e5484d"></label><label class="field">背景色<input id="mgBackground" type="color" value="#17150f"></label><label class="field">音乐<select id="mgMusic"><option value="">不指定</option>'+audio.map(x=>'<option value="'+x.id+'">'+esc(x.name)+'</option>').join('')+'</select></label><div class="field"><span>音效提示</span>'+audio.map(x=>'<label><input type="checkbox" data-mg-sfx="'+x.id+'"> '+esc(x.name)+'</label>').join('')+'</div><button class="action" id="planMgDirector">生成 MG 分镜与动画方案</button>'+(plan?'<div class="caption"><b>场景 '+plan.summary.scenes+' · 数据场景 '+plan.summary.dataScenes+' · 关键帧 '+plan.summary.keyframes+'</b><small>转场 '+plan.summary.transitions+' · Shader '+plan.summary.shaders+' · SFX '+plan.summary.sfx+' · '+(plan.beatAligned?'已对齐节拍':'固定时间')+'</small></div>'+plan.scenes.map(x=>'<div class="caption"><b>'+fmt(x.start)+' '+esc(x.title)+'</b><small>'+esc(x.kind)+' · '+esc(x.shader)+' · '+esc(x.transition)+'</small></div>').join('')+'<button class="save" id="applyMgDirector">确认应用 MG 分镜</button>':'')+(cards.length?'<h3 style="margin-top:22px">文案与数据审核</h3>'+cards.map(x=>'<div class="caption"><b>'+esc(x.title)+'</b><small>'+esc([x.value,x.unit,x.subtitle].filter(Boolean).join(' · '))+' · '+esc(x.factStatus||x.status)+'</small></div>').join('')+(pending.length?'<label class="field"><input type="checkbox" onchange="this.nextElementSibling.disabled=!this.checked"> 我已确认所有文案、数字和单位</label><button class="action" id="reviewMgScenes" disabled>批准 MG 场景</button>':'')+(approved.length?'<button class="save" id="renderMgScenes">渲染 '+approved.length+' 个双层 MG 场景</button>':'')+(rendered.length?'<div class="caption"><b>已渲染 '+rendered.length+' 个 MG 场景</b><small>背景、前景、关键帧、Shader 和转场均可继续编辑</small></div>':''):'')};
